try {
  const rubric = {
    appointment_conversion: { weight: 0.30, description: 'Did the agent successfully guide toward booking?' },
    objection_handling:     { weight: 0.25, description: 'Did the agent address concerns effectively?' },
    conversation_flow:      { weight: 0.15, description: 'Natural pacing, one question at a time, appropriate pauses' },
    information_accuracy:   { weight: 0.15, description: 'Did the agent provide correct practice information?' },
    rapport_building:       { weight: 0.10, description: 'Did the agent build trust and show empathy?' },
    compliance:             { weight: 0.05, description: 'No medical advice, no fabricated availability, proper boundaries' }
  };

  const currentPrompt = $json.current_prompt || 'Use prompts/v1_system_prompt.json contents from repo as current prompt.';

  return [{ json: {
    call: $json,
    current_prompt: currentPrompt,
    rubric
  }}];
} catch (error) {
  return [{ json: { error: String(error), raw_call: $json } }];
}

parameters.jsonBody:
={{ {
  system_instruction: {
    parts: [{
      text: `You are an expert call center quality analyst evaluating AI voice agent performance.

You will receive:
1. A full call transcript or call details
2. The system prompt the agent was using
3. The scoring rubric with 6 dimensions

Your job:
1. Score each dimension 1-5 with a brief justification
2. Calculate the weighted total score (0.0 to 5.0)
3. Identify the TOP 3 specific failure points in the conversation
   - Quote the exact transcript moment if available
   - Explain what went wrong
   - Suggest the specific prompt addition that would fix it
4. Identify what the agent did WELL (reinforce in next version)
5. Check if the agent asked for information already given — flag it as a failure if so
6. Output structured JSON ONLY, no other text`
    }]
  },
  contents: [{
    role: 'user',
    parts: [{
      text: `CALL DATA:\n${JSON.stringify($json.call, null, 2)}\n\nCURRENT PROMPT:\n${$json.current_prompt}\n\nRUBRIC:\n${JSON.stringify($json.rubric, null, 2)}\n\nReturn JSON with keys: scores (object with each dimension name -> {score, justification}), weighted_total, top_failure_points (array of {moment, problem, fix}), strengths_to_preserve (array of strings), prompt_fix_suggestions (array of strings).`
    }]
  }]
} }}

parameters.jsCode:
try {
  const response = $json;
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  let parsed = null;

  const attemptParse = (value) => {
    const trimmed = String(value || '').trim();
    const cleaned = trimmed.startsWith('```')
      ? trimmed.replace(/^```json/, '').replace(/^```/, '').replace(/```$/, '').trim()
      : trimmed;
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    const jsonText = start >= 0 && end > start ? cleaned.slice(start, end + 1) : cleaned;
    return JSON.parse(jsonText);
  };

  try {
    parsed = attemptParse(raw);
  } catch (firstError) {
    try {
      parsed = attemptParse(raw.replace(/\n/g, '\n'));
    } catch (secondError) {
      return [{ json: { parse_error: String(secondError), raw_judge_text: raw, judge_raw_response: response } }];
    }
  }

  return [{ json: { judge: parsed, judge_raw_response: response } }];
} catch (error) {
  return [{ json: { parse_error: String(error), judge_raw_response: $json } }];
}

parameters.jsonBody:
={{ {
  system_instruction: {
    parts: [{
      text: `You are a prompt engineer specializing in voice AI agent optimization.

You will receive:
1. The current system prompt (version N)
2. The judge's evaluation with failure points and suggested fixes

Your job:
1. Apply ONLY the fixes the judge recommended — do not rewrite unrelated sections
2. Preserve everything that scored well (4-5)
3. Add new objection handlers for identified gaps
4. Keep the total prompt under 600 tokens (voice latency constraint)
5. IMPORTANT: Preserve the conversation-history guard — 'Never re-ask information the patient has already given.'
6. IMPORTANT: Preserve the doctor list, the show_confirmation trigger, and the TURN-TAKING RULES sections verbatim
7. Output the complete revised prompt
8. Output a changelog: bullet points of what changed and why (max 5 bullets, be specific)

Output JSON ONLY with keys: revised_prompt (string), changelog (array of strings).`
    }]
  },
  contents: [{
    role: 'user',
    parts: [{
      text: `CURRENT PROMPT:\n${$node['Code Prepare Inputs'].json.current_prompt}\n\nJUDGE OUTPUT:\n${JSON.stringify($json.judge || {}, null, 2)}`
    }]
  }]
} }}

parameters.jsCode:
try {
  const callPayload = $node['Code Prepare Inputs'].json.call || {};
  const judge = $node['Code Parse Judge'].json.judge || {};
  const reviserRaw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';

  let reviser = { revised_prompt: $node['Code Prepare Inputs'].json.current_prompt, changelog: ['No revision output parsed.'] };
  try {
    const start = reviserRaw.indexOf('{');
    const end = reviserRaw.lastIndexOf('}');
    const maybeJson = start >= 0 && end > start ? reviserRaw.slice(start, end + 1) : reviserRaw;
    reviser = JSON.parse(maybeJson);
  } catch (e) {
    reviser = { revised_prompt: reviserRaw || $node['Code Prepare Inputs'].json.current_prompt, changelog: ['Fallback parse path used.'] };
  }

  // Derive next version number
  const currentVersion = callPayload.prompt_version || 'v1';
  const vMatch = String(currentVersion).match(/(\d+)/);
  const nextNum = vMatch ? parseInt(vMatch[1]) + 1 : 2;
  const nextVersion = 'v' + nextNum;

  const analysisReport = {
    iteration: callPayload.iteration || null,
    calls_analyzed: [callPayload.call_id || 'unknown_call'],
    prompt_version_evaluated: currentVersion,
    aggregate_scores: Object.assign({}, judge.scores || {}, { weighted_total: judge.weighted_total || null }),
    top_failure_points: judge.top_failure_points || [],
    strengths_to_preserve: judge.strengths_to_preserve || [],
    prompt_changes: {
      from_version: currentVersion,
      to_version: nextVersion,
      changelog: reviser.changelog || []
    },
    timestamp: new Date().toISOString()
  };

  const promptVersion = {
    version: nextVersion,
    created_at: new Date().toISOString(),
    created_by: 'n8n_analysis_workflow',
    token_count: Math.ceil(String(reviser.revised_prompt || '').length / 4),
    changelog: Array.isArray(reviser.changelog) ? reviser.changelog.join(' | ') : String(reviser.changelog || ''),
    changelog_list: Array.isArray(reviser.changelog) ? reviser.changelog : [String(reviser.changelog || '')],
    prompt: reviser.revised_prompt || '',
    metadata: {
      avg_score_during_use: null,
      calls_made_with_this_version: 0,
      replaced_by: null,
      weighted_total_trigger: judge.weighted_total || null
    }
  };

  const callLog = Object.assign({}, callPayload, {
    judge_scores: judge.scores || {},
    weighted_total: judge.weighted_total || null,
    prompt_fix_suggestions: judge.prompt_fix_suggestions || []
  });

  return [{ json: {
    call_log: callLog,
    analysis_report: analysisReport,
    prompt_version: promptVersion,
    revised_prompt: promptVersion.prompt
  }}];
} catch (error) {
  return [{ json: { error: String(error), raw_call: $node['Code Prepare Inputs'].json.call || {} } }];
}

